# ================================================================ # ⚠️ DEPRECATED — 此脚本已废弃，请使用 verify_email_direct.py # verify_email_direct.py 功能更全，支持： #   - 单条验证 + 批量验证 (--batch) #   - HTTP 服务器模式 (--server) #   - 健康检查 (--health) #   - 自定义请求间隔 (--delay) #   - 更详细的验证结果（9 个字段） # 用法完全兼容：python scripts/verify_email_direct.py --batch emails.txt # ================================================================ #!/usr/bin/env python3 ''' 批量邮箱验证工具 — 调用本地 check-if-email-exists (Reacher) Docker 服务  用法:   python validate_emails.py --input emails.txt   python validate_emails.py --input emails.txt --output results.csv   python validate_emails.py --email test@example.com  输入格式 (emails.txt)：每行一个邮箱地址 输出格式 (CSV)：email, is_reachable, mx, smtp, syntax, catch_all, disposable '''  import argparse import csv import json import sys import time import urllib.request import urllib.error  REACHER_URL = "http://localhost:8080/v0/check_email"   def check_email(email: str) -> dict:     '''验证单个邮箱，调用 Reacher API'''     url = f"{REACHER_URL}?email={email}"     try:         with urllib.request.urlopen(url, timeout=15) as resp:             return json.loads(resp.read())     except urllib.error.URLError as e:         return {"email": email, "error": str(e)}     except json.JSONDecodeError:         return {"email": email, "error": "无效的 JSON 响应"}   def main():     parser = argparse.ArgumentParser(description="批量邮箱验证工具")     parser.add_argument("--input", help="每行一个邮箱的输入文件")     parser.add_argument("--output", help="CSV 输出文件", default="email_results.csv")     parser.add_argument("--email", help="验证单个邮箱")     args = parser.parse_args()      # 单邮箱模式     if args.email:         result = check_email(args.email.strip())         print(json.dumps(result, indent=2, ensure_ascii=False))         return      # 批量模式     if not args.input:         print("[错误] 请提供 --input <文件> 或 --email <地址>")         sys.exit(1)      with open(args.input, "r", encoding="utf-8") as f:         emails = [line.strip() for line in f if line.strip()]      if not emails:         print("[错误] 输入文件中未找到邮箱地址")         sys.exit(1)      print(f"正在验证 {len(emails)} 个邮箱...")     results = []      for i, email in enumerate(emails):         print(f"  [{i+1}/{len(emails)}] {email}", end=" ... ")         result = check_email(email)          if "error" in result:             print(f"错误: {result['error']}")         else:             status = result.get("is_reachable", "unknown")             print(status)          results.append({             "email": email,             "is_reachable": result.get("is_reachable", "unknown"),             "mx": result.get("misc", {}).get("is_mx_found", ""),             "smtp": result.get("misc", {}).get("is_smtp_ok", ""),             "syntax": result.get("syntax", {}).get("is_valid_syntax", ""),             "catch_all": result.get("misc", {}).get("is_catch_all", ""),             "disposable": result.get("misc", {}).get("is_disposable", ""),             "error": result.get("error", ""),         })          # 请求间隔 100ms         time.sleep(0.1)      # 写入输出文件     fieldnames = ["email", "is_reachable", "mx", "smtp", "syntax", "catch_all", "disposable", "error"]     with open(args.output, "w", newline="", encoding="utf-8-sig") as f:         writer = csv.DictWriter(f, fieldnames=fieldnames)         writer.writeheader()         writer.writerows(results)      # 汇总报告     valid = sum(1 for r in results if r["is_reachable"] == "valid")     invalid = sum(1 for r in results if r["is_reachable"] == "invalid")     risky = sum(1 for r in results if r["is_reachable"] == "risky")     unknown = sum(1 for r in results if r["is_reachable"] == "unknown")     errors = sum(1 for r in results if r["error"])      print(f"\n=== 验证结果 ===")     print(f"总数:   {len(results)}")     print(f"有效:   {valid} ({valid/len(results)*100:.0f}%)")     print(f"无效:   {invalid} ({invalid/len(results)*100:.0f}%)")     print(f"有风险: {risky} ({risky/len(results)*100:.0f}%)")     print(f"未知:   {unknown} ({unknown/len(results)*100:.0f}%)")     if errors:         print(f"出错:   {errors}")     print(f"\n结果已保存至: {args.output}")   if __name__ == "__main__":     main()